SELECT algorithm_name, category
FROM algorithms
WHERE algorithm_id = 0;

SELECT *
FROM configurations
WHERE configuration_type = 'string' AND configuration_value LIKE '%error%';

SELECT i.instance_name, r.run_number, r.environment
FROM runs r
JOIN instances i ON r.instance_id = i.instance_id;

SELECT COUNT(DISTINCT algorithm_id) 
FROM runs 
WHERE instance_id = 0;

SELECT parameter_name, parameter_value
FROM parameters
WHERE parameter_id = 0 AND parameter_type = 'float';

SELECT DISTINCT algorithm_name
FROM algorithms
WHERE CAST(version AS REAL) >= 2.0;
